// ---------------- Pending sends (history · 대기 중) ----------------

export type PendingSend = {
  id: string;
  scheduledAt: string;
  campaignName: string;
  channel: Channel;
  sku: Sku;
  expectedCount: number;
  reason: PendingReason;
};

/**
 * Derived from the dashboard timetable's `plan`-type slots — single source of
 * truth. Every pending row surfaces the same data the timetable dotted markers
 * render.
 */
export const mockPendingSends: PendingSend[] = ttSchedules
  .filter((s) => s.type === "plan" && !!s.reason)
  .map((s, i) => ({
    id: `p${i + 1}`,
    scheduledAt: timeslotWhen(s),
    campaignName: s.name,
    channel: s.channel,
    sku: s.sku,
    expectedCount: s.countNum,
    reason: s.reason!,
  }));

